import React from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider } from './context/AuthContext';

// Pages
import Login from './components/auth/Login';
import Register from './components/auth/Register';
import AdminDashboard from './components/admin/AdminDashboard';
import UsersList from './components/admin/UsersList';
import CertificatesList from './components/admin/CertificatesList';
import Statistics from './components/admin/Statistics';
import UserDashboard from './components/user/UserDashboard';
import UserCertificatesList from './components/user/UserCertificatesList';
import CertificateRequestForm from './components/user/CertificateRequestForm';
import UserProfile from './components/user/UserProfile';
import VerifyCertificate from './components/VerifyCertificate';
import NotFound from './components/NotFound';

// Protected Route Components
const AdminRoute = ({ children }) => {
  const token = localStorage.getItem('token');
  const isAdmin = localStorage.getItem('isAdmin') === 'true';
  
  if (!token || !isAdmin) {
    return <Navigate to="/login" />;
  }
  
  return children;
};

const UserRoute = ({ children }) => {
  const token = localStorage.getItem('token');
  
  if (!token) {
    return <Navigate to="/login" />;
  }
  
  return children;
};

function App() {
  return (
    <AuthProvider>
        <Routes>
          {/* Public Routes */}
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />
          <Route path="/verify-certificate" element={<VerifyCertificate />} />
          
          {/* User Routes */}
          <Route path="/dashboard" element={
            <UserRoute>
              <UserDashboard />
            </UserRoute>
          } />
          <Route path="/certificates" element={
            <UserRoute>
              <UserCertificatesList />
            </UserRoute>
          } />
          <Route path="/certificates/request" element={
            <UserRoute>
              <CertificateRequestForm />
            </UserRoute>
          } />
          <Route path="/profile" element={
            <UserRoute>
              <UserProfile />
            </UserRoute>
          } />
          
          {/* Admin Routes */}
          <Route path="/admin" element={
            <AdminRoute>
              <AdminDashboard />
            </AdminRoute>
          } />
          <Route path="/admin/users" element={
            <AdminRoute>
              <UsersList />
            </AdminRoute>
          } />
          <Route path="/admin/certificates" element={
            <AdminRoute>
              <CertificatesList />
            </AdminRoute>
          } />
          <Route path="/admin/statistics" element={
            <AdminRoute>
              <Statistics />
            </AdminRoute>
          } />
          
          {/* Redirects */}
          <Route path="/" element={<Navigate to="/dashboard" />} />
          
          {/* 404 Route */}
          <Route path="*" element={<NotFound />} />
        </Routes>
    </AuthProvider>
  );
}

export default App;
